gtkValueDupExpression <- function(value) {
  .Call("R_gtk_value_dup_expression", value)$result
}


#' @rdname gtk-other
#' @title gtkValueGetExpression
#'
#' @param value GObject.Value
#' @return Expression
#' @export
gtkValueGetExpression <- function(value) {
  .Call("R_gtk_value_get_expression", value)$result
}


#' @rdname gtk-other
#' @title gtkValueSetExpression
#'
#' @param value GObject.Value
#' @param expression Expression
#' @return Return value from C function
#' @export
gtkValueSetExpression <- function(value, expression) {
  .Call("R_gtk_value_set_expression", value, expression)
}


#' @rdname gtk-other
#' @title gtkValueTakeExpression
#'
#' @param value GObject.Value
#' @param expression Expression
#' @return Return value from C function
#' @export
gtkValueTakeExpression <- function(value, expression) {
  .Call("R_gtk_value_take_expression", value, expression)
}


